// fetch-based HTTP helpers (replaces axios to avoid task runner crash)
async function _post(url, data, opts) {
  var headers = {'Content-Type': 'application/json'};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'POST', headers: headers, body: JSON.stringify(data), signal: opts && opts.timeout ? AbortSignal.timeout(opts.timeout) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _get(url, opts) {
  var qurl = url;
  if (opts && opts.params) { var qs = new URLSearchParams(opts.params).toString(); if (qs) qurl += (url.includes('?') ? '&' : '?') + qs; }
  var headers = {};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(qurl, {headers: headers, signal: opts && opts.timeout ? AbortSignal.timeout(opts.timeout) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _del(url, opts) {
  var headers = {'Content-Type': 'application/json'};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'DELETE', headers: headers, body: opts && opts.data ? JSON.stringify(opts.data) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _put(url, body, opts) {
  var headers = {};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'PUT', headers: headers, body: typeof body === 'string' ? body : JSON.stringify(body)});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  return {data: json, status: r.status};
}
const M = 'http://mlflow:5050/api/2.0/mlflow';
const MA = 'http://mlflow:5050/api/2.0/mlflow-artifacts/artifacts';
const body = $input.item.json.body;
const action = body.action;

try {

if (!action) throw new Error('action required: upload, list, get, link');

async function post(path, data) {
  var r = await fetch(M + path, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

async function apiGet(path) {
  var r = await fetch(M + path);
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

// Helper: get or create __datasets experiment
async function getDatasetExperiment() {
  try {
    var res = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__datasets'));
    return res.experiment.experiment_id;
  } catch(e) {
    var cr = await post('/experiments/create', {name: '__datasets'});
    return cr.experiment_id;
  }
}

if (action === 'upload') {
  var name = body.name;
  if (!name) throw new Error('name required');
  var rows = body.rows || [];
  var schema = body.schema || [];
  var format = body.format || 'jsonl';
  var expId = await getDatasetExperiment();
  var startTime = Date.now();
  var runRes = await post('/runs/create', {
    experiment_id: expId,
    start_time: startTime,
    run_name: name
  });
  var runId = runRes.run.info.run_id;
  var preview = rows.slice(0, 5).map(function(r) { return JSON.stringify(r); }).join('\n');
  await post('/runs/log-batch', {
    run_id: runId,
    params: [
      {key: 'dataset_name', value: name},
      {key: 'format', value: format},
      {key: 'row_count', value: String(rows.length)},
      {key: 'schema', value: JSON.stringify(schema)}
    ],
    tags: [
      {key: 'mlflow.note.content', value: preview.substring(0, 5000)},
      {key: 'dataset_name', value: name}
    ]
  });
  // FR-001: Store full rows as JSONL artifact
  if (rows.length > 0) {
    var jsonl = rows.map(function(r) { return JSON.stringify(r); }).join('\n');
    var artUrl = MA + '/' + expId + '/' + runId + '/artifacts/rows.jsonl';
    await _put(artUrl, jsonl, {headers: {'Content-Type': 'text/plain'}});
  }
  await post('/runs/update', {run_id: runId, status: 'FINISHED', end_time: Date.now()});
  return {action: 'upload', name: name, run_id: runId, row_count: rows.length, format: format};
}

if (action === 'list') {
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__datasets'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    return {action: 'list', datasets: [], count: 0};
  }
  var limit = body.limit || 50;
  var searchRes = await post('/runs/search', {
    experiment_ids: [expId],
    max_results: limit,
    order_by: ['start_time DESC']
  });
  var datasets = (searchRes.runs || []).map(function(run) {
    var info = run.info || {};
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    return {
      run_id: info.run_id,
      name: params.dataset_name || info.run_name || '',
      format: params.format || 'jsonl',
      row_count: Number(params.row_count || 0),
      schema: params.schema ? JSON.parse(params.schema) : [],
      created_at: Number(info.start_time)
    };
  });
  return {action: 'list', datasets: datasets, count: datasets.length};
}

if (action === 'get') {
  var runId = body.run_id;
  if (!runId) throw new Error('run_id required');
  var runResp = await apiGet('/runs/get?run_id=' + encodeURIComponent(runId));
  var run = runResp.run;
  var info = run.info || {};
  var params = {};
  (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
  var tags = {};
  (run.data && run.data.tags || []).forEach(function(t) { tags[t.key] = t.value; });
  var result = {
    action: 'get',
    run_id: runId,
    name: params.dataset_name || info.run_name || '',
    format: params.format || 'jsonl',
    row_count: Number(params.row_count || 0),
    schema: params.schema ? JSON.parse(params.schema) : [],
    preview: tags['mlflow.note.content'] || '',
    created_at: Number(info.start_time)
  };
  // FR-002: Return full rows when requested
  if (body.include_rows) {
    try {
      var artUrl = MA + '/' + info.experiment_id + '/' + runId + '/artifacts/rows.jsonl';
      var artResp = await _get(artUrl, {responseType: 'text'});
      var lines = String(artResp.data).split('\n').filter(function(l) { return l.trim(); });
      result.rows = lines.map(function(l) { return JSON.parse(l); });
      result.rows_available = true;
    } catch(artErr) {
      result.rows_available = false;
    }
  }
  return result;
}

if (action === 'link') {
  var evalRunId = body.run_id;
  var datasetName = body.dataset_name;
  var digest = body.digest || 'n/a';
  if (!evalRunId || !datasetName) throw new Error('run_id and dataset_name required');
  await post('/runs/log-inputs', {
    run_id: evalRunId,
    datasets: [{
      dataset: {
        name: datasetName,
        digest: digest,
        source_type: 'local',
        source: datasetName
      },
      tags: body.tags || []
    }]
  });
  return {action: 'link', run_id: evalRunId, dataset_name: datasetName, status: 'linked'};
}

throw new Error('Unknown action: ' + action);

} catch(e) {
  var msg = e.message || String(e);
  if (e.response && e.response.data) msg += ' | ' + JSON.stringify(e.response.data);
  var status = 400;
  if (e.response && e.response.status === 404) status = 404;
  if (msg.indexOf('RESOURCE_DOES_NOT_EXIST') !== -1) status = 404;
  return {error: true, message: msg, action: action || 'unknown', _status: status};
}
